function boardFromRows(rows:string[]){
  // rows are emoji separated by spaces; map to indices via map
  const map = {'🍎':0,'🍋':1,'🍇':2,'🍒':3,'🍊':4,'🍑':5};
  const arr:number[] = [];
  for(const r of rows){
